class Solution(object):
    def compressedString(self, word):
        res = []
        i = 0
        while i < len(word):
            c = word[i]
            count = 0
            while i < len(word) and word[i] == c and count < 9:
                count += 1
                i += 1
            res.append(str(count) + c)
        return ''.join(res)
